def has_cycle(graph):
    """
    Belirtilen yönsüz grafikte döngü olup olmadığını kontrol eder.

    Graf, bir komşuluk listesi olarak temsil edilir; burada anahtarlar düğümlerdir
    ve değerler komşu düğümlerin listesidir.

    Args:
        graph: Yönsüz grafiği temsil eden bir sözlük.
               Örnek: {0: [1, 2], 1: [0, 2], 2: [0, 1]}

    Returns:
        Grafikte döngü varsa True, aksi takdirde False.
    """
    visited = set()

    def dfs(node, parent):
        visited.add(node)

        for neighbor in graph.get(node, []):
            if neighbor == parent:
                continue
            if neighbor in visited:
                return True  # Döngü bulundu
            if dfs(neighbor, node):
                return True  # Rekürsif aramada döngü bulundu

        return False  # Bu yoldan döngü bulunamadı

    for node in graph:
        if node not in visited:
            # Her bir bağlı bileşen için DFS başlat
            # Başlangıç düğümünün ebeveyni yoktur, bu yüzden None kullanılır.
            if dfs(node, None):
                return True
    return False
